const inputData = $input.first()?.json || {};

const chat_id = inputData.data?.chat_id || inputData.chat_id;
const ai_response = inputData.data?.ai_response || inputData.ai_response;

// Validation Sandwich PRE: Check required fields
if (!chat_id || !ai_response) {
  return [{
    json: {
      isValid: false,
      error_code: "VALIDATION_ERROR",
      error_message: "Missing required fields 'chat_id' or 'ai_response'"
    }
  }];
}

return [{
  json: {
    isValid: true,
    chat_id: chat_id,
    ai_response: ai_response
  }
}];

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
        chat_id: $node["Is Valid?"].json.chat_id,
        delivery_status: "SENT"
    },
    _meta: {
      source: "NN_04_Telegram_Sender",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_04",
      version: "1.0"
    }
  }
}];

return [{
  json: {
    success: false,
    error_code: $json.error_code,
    error_message: $json.error_message,
    data: null,
    _meta: {
      source: "NN_04_Telegram_Sender",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_04",
      version: "1.0"
    }
  }
}];

return [{
  json: {
    success: false,
    error_code: "INTERNAL_ERROR",
    error_message: $json.message || "Workflow execution failed",
    data: null,
    _meta: {
      source: "NN_04_Telegram_Sender",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_04",
      version: "1.0"
    }
  }
}];
